def get_all_roles_for_user(user):
    if hasattr(user, 'userreg'):
        return list(user.userreg.role.values_list('role', flat=True))
    return []

class Login(View):
    # Map department names to their respective department codes
    DEPARTMENT_CODE_MAP = {
        "Engineering R&D": "01",
        "Production": "02",
        "IMM": "03",
        "Accounts": "04",
        "Administration": "06",
        "HR": "07",
        "IT": "08",
        "Marketing": "09",
    }

    def get(self, request):
        # Render login page on GET request
        return render(request, 'ims/login.html')

    def post(self, request):
        # Get employee_id and password from submitted form
        employee_id = request.POST.get('employee_id')
        password = request.POST.get('password')

        response = None
        try:
            # Attempt external authentication service request
            response = requests.post(
                "http://192.168.10.86:8007/login/",
                data={"emp_id": employee_id, "password": password},
                timeout=1  # Timeout set to 1 second
            )
        except ConnectionError:
            # Handle failure to connect to external service gracefully
            print("Unable to connect to the external service. Falling back to local authentication.")
        except requests.RequestException as e:
            # Catch other requests exceptions and log them
            print(f"Error with external service: {str(e)}")
        # #pdb.set_trace
        # If external service responds successfully
        if response and response.status_code == 200:
            data = response.json()
            user_details = data.get('user_details')

            if user_details:
                # Get department name and map to code using predefined map
                department_name = user_details['department']
                department_code = self.DEPARTMENT_CODE_MAP.get(department_name)

                if not department_code:
                    # Return error if no code found for department name
                    return JsonResponse({'success': False, 'error': 'Department code not found for the given department name.'})

                # Get or create department instance in DB
                department_instance, created = Department.objects.get_or_create(
                    dept_name=department_name,
                    defaults={'dept_code': department_code}
                )
                
                # Process roles from user details; support single string or list of roles
                role_instance = []
                if user_details.get('role'):
                    roles = user_details['role']
                    if isinstance(roles, str):
                        roles = [roles]
                    for r in roles:
                        obj, created = Roles.objects.get_or_create(role=r)
                        role_instance.append(obj)

                # Handle designation: get or create if not existing
                if user_details.get('designation'):
                    try:
                        designation_instance = Designation.objects.get(designation=user_details['designation'])
                    except Designation.DoesNotExist:
                        designation = Designation()
                        designation.designation = user_details['designation']
                        designation.save()
                        designation_instance = designation
                else:
                    designation_instance = None

                # Retrieve manager user if exists
                if user_details.get('manager'):
                    try:
                        manager_instance = UserReg.objects.get(emp_id=user_details['manager'])
                    except UserReg.DoesNotExist:
                        manager_instance = None
                else:
                    manager_instance = None

                # Retrieve director user if exists
                director_instance = None
                if user_details.get('director'):
                    try:
                        director_instance = UserReg.objects.get(emp_id=user_details['director'])
                    except Director.DoesNotExist:
                        director_instance = None

                # Retrieve main user object by username from user details
                user = UserReg.objects.get(username=user_details['user'])

                # Get or create user profile with provided details
                user_profile, created = UserReg.objects.get_or_create(
                    emp_id=user_details['emp_id'],
                    defaults={
                        'user': user,
                        'emp_id': user_details['emp_id'],
                        'email_id': user_details['email_id'],
                        'alternate_email': user_details.get('alternate_email', ''),
                        'gender': user_details.get('gender', ''),
                        'phone_number': user_details['phone_number'],
                        'designation': designation_instance,
                        'user_dept': department_instance,
                        'manager': manager_instance,
                        'director': director_instance
                    }
                )

                # If profile exists, update fields
                if not created:
                    user_profile.user = user
                    user_profile.emp_id = user_details['emp_id']
                    user_profile.email_id = user_details['email_id']
                    user_profile.alternate_email = user_details.get('alternate_email', '')
                    user_profile.phone_number = user_details['phone_number']
                    user_profile.designation = designation_instance
                    user_profile.user_dept = department_instance
                    user_profile.manager = manager_instance
                    user_profile.director = director_instance
                    user_profile.save()

                # Assign roles to user profile if roles exist
                if role_instance:
                    user_profile.role.set(role_instance)

                # Log in the user with Django auth system
                login(request, user_profile)
                    
                
                # Set session variables for easy access
                roles_list = [r.role for r in user_profile.role.all()]
                request.session['user_role'] = roles_list

                if "Indentor" in roles_list and len(roles_list) > 1:
                    non_indentor_roles = [r for r in roles_list if r != "Indentor"]
                    request.session['active_role'] = non_indentor_roles[0]
                else:
                    request.session['active_role'] = roles_list[0] if roles_list else None


                request.session['user_name'] = user_profile.emp_id
                request.session['emp_id'] = user_profile.emp_id

                # Respond with success and redirect URL based on role
                return JsonResponse({
                    'success': True,
                    'employee_id': user_profile.emp_id,
                    'redirect_url': self.get_redirect_url(role_instance[0].role if role_instance else '')
                })
            else:
                # No user details found in response - invalid login
                return JsonResponse({'success': False, 'error': 'Invalid login credentials.'})

        else:
            # If external service fails, fallback to local DB authentication
            try:
                user_profile = UserReg.objects.get(emp_id=employee_id)
                if not user_profile.is_active:
                    return JsonResponse({'success': False, 'error': 'User account is inactive.'})

                user = user_profile.user  # Get the associated Django User model

                # Check password locally
                if user and user.check_password(password):
                    login(request, user)
                    # ##pdb.set_trace
                    # Set session details on successful login
                    roles_list = [r.role for r in user_profile.role.all()]
                    request.session['user_role'] = roles_list

                    if "Indentor" in roles_list and len(roles_list) > 1:
                        non_indentor_roles = [r for r in roles_list if r != "Indentor"]
                        request.session['active_role'] = non_indentor_roles[0]
                    else:
                        request.session['active_role'] = roles_list[0] if roles_list else None

                    # request.session['active_role'] = user_profile.role.first().role
                    request.session['user_name'] = f"{user.first_name} {user.last_name}"
                    request.session['emp_id'] = user_profile.emp_id
                    return JsonResponse({
                        'success': True,
                        'employee_id': user_profile.emp_id,
                        'redirect_url': self.get_redirect_url(request.session.get('active_role', ''))

                    })
                else:
                    # Password check failed
                    return JsonResponse({'success': False, 'error': 'Invalid credentials.'})

            except UserReg.DoesNotExist:
                # No user found in local DB either
                return JsonResponse({'success': False, 'error': 'User does not exist.'})

    def get_redirect_url(self, role_name):
        # Return different redirect URLs based on the user's role
        if role_name == 'Recommending Authority':
            return reverse('ra_dashboard')
        elif role_name == 'Accounts':
            return reverse('acc_dashboard')
        elif role_name == 'IMM':
            return reverse('imm_dashboard')
        elif role_name == 'Indentor':
            return reverse('indentor_dashboard')
        elif role_name == 'Approving Authority':
            return reverse('aa_dashboard')
        elif role_name == 'CEO':
            return reverse('acc_dashboard')
        elif role_name == 'GM':
            return reverse('acc_dashboard')
        elif role_name == 'Purchase Assistant':
            return reverse('imm_dashboard')
        else:
            return reverse('vendor')

def get_redirect_url(role_name):
    # Return different redirect URLs based on the user's role
    if role_name == 'Recommending Authority':
        return reverse('ra_dashboard')
    elif role_name == 'Accounts':
        return reverse('acc_dashboard')
    elif role_name == 'IMM':
        return reverse('imm_dashboard')
    elif role_name == 'Indentor':
        return reverse('indentor_dashboard')
    elif role_name == 'Approving Authority':
        return reverse('aa_dashboard')
    elif role_name == 'Purchase Assistant':
        return reverse('imm_dashboard')
    else:
        return reverse('vendor') 
