class ProfileView(LoginRequiredMixin, View):
    login_url = reverse_lazy('login')

    @method_decorator(csrf_exempt)
    def dispatch(self, *args, **kwargs):
        return super().dispatch(*args, **kwargs)

    def get(self, request):
        # Fetch all departments, roles, and designations
        departments = Department.objects.all()
        roles = Roles.objects.all()
        desig = Designation.objects.all()

        # Fetch logged-in user's UserReg info
        try:
            userreg = UserReg.objects.get(user=request.user)
            emp_id = userreg.emp_id
            first_name = request.user.first_name
            last_name = request.user.last_name
            profile_img = userreg.profile_img
            email = userreg.email_id
            phoneno=userreg.phone_number
            roles_list = list(userreg.role.values_list('role', flat=True))
            # Get department name if exists
            department = userreg.user_dept.dept_name if userreg.user_dept else None
            sign_upload=''
            sign_upload = userreg.sign.url if userreg.sign else None
            sign_filename = ''
            if userreg.sign:
                sign_filename = userreg.sign.name.split('/')[-1] if userreg.sign else None   # get filename from FileField path
  
        except UserReg.DoesNotExist:

            emp_id = None
            first_name = ''
            last_name = ''
            email = ''
            department = ''
            roles_list = []
            sign_filename=''
            sign_upload=''

        context = {
            'departments': departments,
            'roles': roles,
            'desig': desig,
            'phoneno':phoneno,
            'emp_id': emp_id,
            'first_name': first_name,
            'last_name': last_name,
            'email': email,
            'department': department,
            'roles_list': roles_list,
            
            'profile_img': profile_img,
            'sign_upload': sign_upload,
            'sign_filename': sign_filename,
        }

        return render(request, 'ims/profile.html', context)

    def post(self, request):
        ##pdb
        # Handle employee ID validation via AJAX
        if request.headers.get('x-requested-with') == 'XMLHttpRequest' and request.POST.get('employee_id') and not request.POST.get('password'):
            employee_id = request.POST.get("employee_id")
            if not UserReg.objects.filter(emp_id=employee_id).exists():
                return JsonResponse({'valid': False, 'message': 'Invalid Employee ID'}, status=404)
            return JsonResponse({'valid': True, 'message': 'Valid Employee ID'})

        # Otherwise, process full profile update (profile pic + sign + password)
        user = request.user
        try:
            user_reg = UserReg.objects.get(user=user)
        except UserReg.DoesNotExist:
            return JsonResponse({'status': 'error', 'message': 'User profile not found'}, status=404)

        profile_pic = request.FILES.get("profile_pic_upload")
        sign = request.FILES.get("sign_upload")
        password = request.POST.get("password")
        phone_number = request.POST.get("phoneno")
        confirm_password = request.POST.get("confirmpassword")

        # ===================== Password validation block =====================
        if password or confirm_password:
            if password != confirm_password:
                return JsonResponse({'status': 'error', 'message': 'Passwords do not match'}, status=400)

            if len(password) < 8:
                return JsonResponse({'status': 'error', 'message': 'Password is too short, must be at least 8 characters'}, status=400)

            if check_password(password, user.password):
                return JsonResponse({'status': 'error', 'message': 'New password cannot be the same as the old password'}, status=400)

            user.set_password(password)
            user.save()

        # ===================== File uploads =====================
        if profile_pic:
            user_reg.profile_img = profile_pic

        if sign:
            user_reg.sign = sign

        if phone_number:
            user_reg.phone_number = phone_number

        user_reg.save()

        return JsonResponse({
            'status': 'success',
            'message': 'Profile updated successfully',
            'profile_img_url': user_reg.profile_img.url if user_reg.profile_img else ''
        })



class RegisterUserView(LoginRequiredMixin, View):
    # If not logged in, redirect to login page
    login_url = reverse_lazy('login') 

    # Disable CSRF protection for dispatch (not recommended for production unless necessary)
    @method_decorator(csrf_exempt)
    def dispatch(self, *args, **kwargs):
        return super().dispatch(*args, **kwargs)

    # Handle GET requests to display registration form
    def get(self, request):
        # Fetch all departments from the database
        departments = Department.objects.all()
        # Fetch all roles
        roles = Roles.objects.all()
        # Fetch all designations
        desig = Designation.objects.all()

        # Fetch all registered users along with related department and designation in optimized queries
        users = UserReg.objects.select_related('designation', 'user_dept').prefetch_related('role').all()

        user_data = []
        # Prepare a list of user info dictionaries to send to the frontend
        for user in users:
            user_data.append({
                'emp_id': user.emp_id,
                'email': user.email_id,
                'phone': user.phone_number,
                'department': user.user_dept.dept_name if user.user_dept else '',
                'designation': user.designation.designation if user.designation else '',
                'gender': user.gender,
                'roles': [role.role for role in user.role.all()],
                'firstname': user.user.first_name if user.user else '',
                 'is_active': user.user.is_active if user.user else False,
                'lastname': user.user.last_name if user.user else ''
                
            })
        #print(user_data,'user_data')
        # Prepare context for rendering template
        context = {
            'departments': departments,
            'roles': roles,
            'desig': desig,
            'users': user_data,
        }

        # Render the user registration HTML page with context data
        return render(request, 'ims/userreg.html', context)
    def post(self, request):
        # #pdb.set_trace
        # Extract data from request.POST as you did
        firstname = request.POST.get('firstname')
        lastname = request.POST.get('lastname')
        phoneno = request.POST.get('phoneno')
        email = request.POST.get('email')
        empid = request.POST.get('empid')
        desig = request.POST.get('desig')
        dept = request.POST.get('dept')
        gender = request.POST.get('gender')
        roles = request.POST.getlist('roles[]')  # List of role IDs as strings
        password = request.POST.get('password')
        confirmpassword = request.POST.get('confirmpassword')
        status = request.POST.get('status', 'Active')
        is_active = True if status == 'Active' else False
        username = firstname  # or however you want to assign username

        if password != confirmpassword:
            return JsonResponse({'success': False, 'error': 'Passwords do not match.'})

        try:
            user_reg = UserReg.objects.filter(emp_id=empid).first()

            if user_reg:
                user = user_reg.user

                # Get current role IDs as strings
                current_roles_set = set(str(role.id) for role in user_reg.role.all())
                new_roles_set = set(roles)

                # Identify removed roles
                removed_roles = current_roles_set - new_roles_set

                # Map role IDs to Procurement model user fields
                role_to_procurement_field = {
                    '1': 'user',         # Example: role id '1' = Indentor (PR raiser)
                    '2': 'ra_user',      # '2' = RA
                    '3': 'imm_user',
                    '4': 'account_user',
                    '5': 'aa_user',
                    '6': 'ri_user',
                    # Add all roles you have, with actual role IDs here
                }

                # Check if user has related PRs for any removed role
                for removed_role_id in removed_roles:
                    proc_field = role_to_procurement_field.get(removed_role_id)
                    if proc_field:
                        filter_kwargs = {proc_field: user}
                        if Procurement.objects.filter(**filter_kwargs).exists():
                            role_obj = user_reg.role.model.objects.filter(id=removed_role_id).first()
                            role_name = role_obj.role if role_obj else removed_role_id
                            return JsonResponse({
                                'success': False,
                                'error': f"Cannot remove role '{role_name}' because user has related PRs."
                            })

                # Update user details
                user.first_name = firstname
                user.last_name = lastname
                user.username = empid
                user.is_active = is_active
                user.mobile_number=phoneno
                if password:
                    user.set_password(password)
                user.save()

                # Update UserReg
                user_reg.username = username
                user_reg.is_active = is_active
                user_reg.email_id = email
                user_reg.phone_number = phoneno
                user_reg.designation_id = desig if desig else None
                user_reg.user_dept_id = dept if dept else None
                user_reg.save()

                if roles:
                    user_reg.role.set(roles)

                return JsonResponse({
                    'success': True,
                    'message': 'User Updated successfully.',
                    'user': {
                        'emp_id': empid,
                        'name': f"{firstname} {lastname}",
                        'email': email,
                        'phone': phoneno,
                        'department': str(user_reg.user_dept) if user_reg.user_dept else "",
                        'designation': str(user_reg.designation) if user_reg.designation else "",
                        'roles': [role.role for role in user_reg.role.all()],
                        'is_active': user.is_active
                    }
                })

            else:
                # Create new user logic as you had
                user = User.objects.create_user(
                    username=empid,
                    first_name=firstname,
                    last_name=lastname,
                    password=password,
                    mobile_number=phoneno
                )
                user.is_active = is_active
                user.save()

                user_reg = UserReg.objects.create(
                    user=user,
                    emp_id=empid,
                    username=username,
                    email_id=email,
                    alternate_email=None,
                    gender=gender,
                    is_active=is_active,
                    phone_number=phoneno,
                    designation_id=desig if desig else None,
                    user_dept_id=dept if dept else None,
                    manager_id=None,
                    director_id=None
                )

                if roles:
                    user_reg.role.set(roles)

                return JsonResponse({
                    'success': True,
                    'message': 'User Created successfully.',
                    'user': {
                        'emp_id': empid,
                        'name': f"{firstname} {lastname}",
                        'email': email,
                        'phone': phoneno,
                        'department': str(user_reg.user_dept) if user_reg.user_dept else "",
                        'designation': str(user_reg.designation) if user_reg.designation else "",
                        'gender': gender,
                        'roles': [str(role) for role in user_reg.role.all()],
                        'is_active': user.is_active
                    }
                })

        except Exception as e:
            return JsonResponse({'success': False, 'error': str(e)})
def switch_role(request):
    new_role = request.GET.get('role')
    if new_role and new_role in request.session.get('user_role', []):
        request.session['active_role'] = new_role
        redirect_url = get_redirect_url(new_role)
        return JsonResponse({'success': True, 'redirect_url': redirect_url})
 
    return JsonResponse({'success': False, 'message': 'Invalid role or role switch not allowed.'}, status=400)

@method_decorator(csrf_exempt, name='dispatch')  # Remove if you handle CSRF properly
class ToggleUserStatusView(View):

    def post(self, request, *args, **kwargs):
        ##pdb
        emp_id = request.POST.get('emp_id')
        if not emp_id:
            return JsonResponse({'status': 'error', 'message': 'Missing emp_id'}, status=400)

        user_reg = get_object_or_404(UserReg, emp_id=emp_id)
        user_reg.is_active = not user_reg.is_active
        user_reg.save()

        return JsonResponse({'status': 'success', 'is_active': user_reg.is_active})

class CustomLogoutView(View):
    def get(self, request):
        logout(request)
        return redirect('login')


class ForgotPasswordView(View):
    
    template_name = 'ims/forgot_password.html'

    def get(self, request):
        return render(request, self.template_name)

    def post(self, request):
        # Check if it's an AJAX request to validate employee ID only
        if request.headers.get('x-requested-with') == 'XMLHttpRequest' and request.POST.get('employee_id') and not request.POST.get('new_password'):
            employee_id = request.POST.get("employee_id")
            if not UserReg.objects.filter(emp_id=employee_id).exists():
                return JsonResponse({'valid': False, 'message': 'Invalid Employee ID'}, status=404)
            return JsonResponse({'valid': True, 'message': 'Valid Employee ID'})

        # Handle full password reset logic
        employee_id = request.POST.get("employee_id")
        # ###########################################pdb  
        new_password = request.POST.get("new_password")
        confirm_password = request.POST.get("confirm_password")

        if new_password != confirm_password:
            return JsonResponse({'status': 'error', 'message': 'Passwords do not match'}, status=400)

        if len(new_password) < 8:
            return JsonResponse({'status': 'error', 'message': 'Password is too short, must be at least 8 characters'}, status=400)
        
        try:
            user_reg = UserReg.objects.get(emp_id=employee_id)
            user = user_reg.user
        except UserReg.DoesNotExist:
            return JsonResponse({'status': 'error', 'message': 'Invalid Employee ID'}, status=404)
        if check_password(new_password, user.password):
            return JsonResponse({'status': 'error', 'message': 'New password cannot be the same as the old password'}, status=400)

        user.set_password(new_password)
        user.save()
        user_reg.save()

        return JsonResponse({'status': 'success', 'message': 'Password updated successfully'})



def generate_procurement_id(source_type, procurement_type_name, category_events, project_code, is_draft=True):
    from datetime import datetime

    fiscal_year = datetime.now().year % 100

    # Determine source code
    if category_events == "Sub_Contract":
        source_code = "3"
    elif category_events == "Service_Contract":
        source_code = "6"
    elif category_events == "Meslova_Material":
        source_code = "7"
    elif source_type == "Import" and procurement_type_name == "Revenue":
        source_code = "1"
    elif source_type == "Indigenous" and procurement_type_name == "Revenue":
        source_code = "2"
    elif procurement_type_name == "Capital":
        source_code = "4"
    else:
        source_code = "8"

    # Build base ID
    base_id = f"{source_code}{project_code}"
    if is_draft:
        base_id += "D"

    # Get all procurement records
    qs = Procurement.objects.all()
    if is_draft:
        qs = qs.filter(procurement_id__contains='D')
    else:
        qs = qs.exclude(procurement_id__contains='D')

    # Extract last 5 digits, take 3rd, 4th, 5th from end (i.e., -5:-2)
    last_serial = 0
    for record in qs:
        pr_id = record.procurement_id
        try:
            if is_draft:
                # For drafts, no fiscal year, so just take last 3 digits
                serial_part = pr_id[-5:-2]
            else:
                # For final IDs, remove last 2 digits (fiscal year)
                # Then take 3 digits before that
                serial_part = pr_id[-5:-2]

            if serial_part.isdigit():
                last_serial = max(last_serial, int(serial_part))
        except Exception:
            continue  # Skip malformed IDs

    # Generate next serial
    new_serial = last_serial + 1
    new_serial_str = f"{new_serial:03d}"

    # Construct new ID
    final_id = f"PR{base_id}{new_serial_str}{fiscal_year:02d}"


    # Ensure uniqueness
    while Procurement.objects.filter(procurement_id=final_id).exists():
        new_serial += 1
        new_serial_str = f"{new_serial:03d}"
        final_id = f"PR{base_id}{new_serial_str}{fiscal_year:02d}"


    return final_id


def generate_particular_id(procurement_id):
    """
    Generate particular IDs even with M2M relationship.
    Format: <procurement_id> - <serial>
    """
    base = procurement_id
    # #######pdb.set_trace

    # Find all Particulars linked to this procurement
    linked_particulars = Particular.objects.filter(
        procurement__procurement_id=procurement_id
    )

    # Extract current max serial
    max_serial = 0
    for p in linked_particulars:
        if p.particular_id and p.particular_id.startswith(base):
            try:
                serial = int(p.particular_id.split("-")[1])
                max_serial = max(max_serial, serial)
            except:
                pass

    new_serial = max_serial + 1
    return f"{base} - {new_serial:02d}"


