def get_all_pos_with_latest_dpo(procurement):
    pos_data = []

    # Fetch all POs for the procurement
    pos = Purchase_Order.objects.filter(procurement=procurement)

    for po in pos:
        draft_dpo = po.draft_po

        # Default vendor & particulars in case there is no DPO
        vendor_data = []
        particular_data_dpo = []
        dpoid = None
        dpo_date = None
        discount = 0.0
        packingcharges = 0.0
        gst_percentage = None
        gst_value = None
        grand_total = float(po.po_grandtotal or 0.0)
        termcond = ''
        gentermcond = ''

        # If DPO exists → use DPO details
        if draft_dpo:
            latest_dpo = DPO.objects.filter(id=draft_dpo.id).order_by('-date').first()
            if latest_dpo:
                dpoid = latest_dpo.dpoid
                dpo_date = latest_dpo.date

                # Vendor info
                vendor = latest_dpo.sources
                if vendor:
                    vendor_data = [{
                        'vendor_id': vendor.code,
                        # 'vendor_name': vendor.vendor_name,
                        'email': vendor.email_1,
                        'phone_number': vendor.phone_number_1,
                        # 'gst_number': vendor.gst_number,
                        'address': vendor.building_name,
                        # 'tin_number': vendor.tin_number,
                        'country': vendor.country.name if vendor.country else '',
                        'state': vendor.state.name if vendor.state else '',
                        'sublocation' : vendor.sublocation.name if vendor.sublocation else '', 
                        # 'city': vendor.city,
                        'pincode': vendor.zipcode,
                        'company_name': vendor.company_name1,
                    }]

                # Particulars from DPO
                for particular in latest_dpo.particular.all():
                    negotiation = particular.negotiation
                    particular_data_dpo.append({
                        'description': particular.description or '',
                        'quantity_dpo': particular.quantity_dpo or '',
                        'partno': particular.partno_dpo or '',
                        'modelno': particular.modelno_dpo or '',
                        'unitname': str(particular.units_dpo) if particular.units_dpo else (particular.unit_display or ''),
                        'unit_price_dpo': str(particular.unit_price_dpo or ''),
                        'total_value': str(particular.total_value or ''),
                        'negotiated_value': negotiation.negotiated_price if negotiation else '',
                        'negotiated_tax': negotiation.negotiated_taxes if negotiation else '',
                    })

                discount = float(latest_dpo.discount or 0.0)
                packingcharges = float(latest_dpo.packingcharges or 0.0)
                gst_percentage = float(latest_dpo.gst_percentage) if latest_dpo.gst_percentage is not None else None
                gst_value = float(latest_dpo.gst_value) if latest_dpo.gst_value is not None else None
                grand_total = float(latest_dpo.grand_total or 0.0)
                termcond = latest_dpo.termcond
                gentermcond = latest_dpo.gentermcond
                total_value = float(sum(p.total_value for p in latest_dpo.particular.all()))

        # ---- Get PO Approvers ----
        po_selected_users = []
        for approval in POApproval.objects.filter(po=po).select_related("user"):
            user = approval.user
            if not user:
                continue

            user_reg = getattr(user, "userreg", None)
            if not user_reg:
                continue

            roles = list(user_reg.role.values_list("role", flat=True))

            # Ignore "Indentor" if multiple roles
            if len(roles) > 1 and "Indentor" in roles:
                roles = [r for r in roles if r != "Indentor"]

            role_to_show = roles[0] if roles else "N/A"
            po_selected_users.append(f"{user.first_name} - {role_to_show}")

        # ---- Build PO Entry ----
        po_entry = {
            'poid': f"PO-{po.po_number}",
            'po_date': po.date_created,
            'dpoid': dpoid,
            'dpo_date': dpo_date,
            'approvers': po_selected_users,
            'vendor_data': vendor_data,
            'particulars': particular_data_dpo,
            #'total_value': float(po.basic_value or 0.0),
            'total_value' : total_value or float(po.basic_value or 0.0),
            'discount': discount,
            'po_files': po.po_files.url if po.po_files else None,
            'packingcharges': packingcharges,
            'gst_percentage': gst_percentage,
            'gst_value': gst_value or float(po.gst_value or 0.0),
            'grand_total': grand_total,
            'billing_address_1': getattr(draft_dpo, 'billing_address_1', None) if draft_dpo else None,
            'delivery_address_2': getattr(draft_dpo, 'delivery_address_2', None) if draft_dpo else None,
            'form_type': 'import' if procurement.import_indigenous and procurement.import_indigenous.source_code == "02" else 'indigenous',
            'termcond': termcond,
            'gentermcond': gentermcond,
            'postage': {
                'stageid': po.postage.id if po.postage else None,
                'stage': po.postage.stagename.stage if po.postage and po.postage.stagename else None,
                'remarktype': po.postage.remarktype if po.postage else None,
            }
        }

        pos_data.append(po_entry)

    return pos_data


class RAProcurementView(LoginRequiredMixin, View):
    login_url = reverse_lazy('login')
    
    @method_decorator(csrf_exempt)
    def dispatch(self, *args, **kwargs):
        return super().dispatch(*args, **kwargs)

    def get(self, request):
        user = request.user

        try:
            user_reg = UserReg.objects.get(user=request.user)
            roles = user_reg.role.all()
            role_names = request.session.get('active_role')
        except UserReg.DoesNotExist:
            return redirect('login')

        # Role based redirects
        if "Recommending Authority" in role_names:
            request.session["last_url"] = request.path
        elif "IMM" in role_names or "Purchase Assistant" in role_names:
            return redirect('imm_dashboard')
        elif "Indentor" in role_names:
            return redirect('indentor_dashboard')
        elif "Accounts" in role_names:
            return redirect('acc_dashboard')
        elif "Approving Authority" in role_names:
            return redirect('aa_dashboard')
        else:
            return redirect(request.session.get("last_url", "/"))

        # Get procurement data
        data = get_ra_procurement_data(request,user)

        return render(request, 'ims/ra_procurement.html', data)
   
    def post(self, request):
        procurement_id = request.POST.get('id')
        procurement = Procurement.objects.get(procurement_id=procurement_id)
        selected_user = request.POST.get('selected_user')
        remarks = request.POST.get('remarks')
        stage_action = request.POST.get('stage_action')
        role = request.POST.get('role')
        suppliers = procurement.supplier.all()
        supplier_values = [supplier.company_name1 for supplier in suppliers]
        ist = pytz.timezone('Asia/Kolkata')  
        enquiry_suppliers = EnquirySupplierPR.objects.filter(procure=procurement)
