# View related to the Role Account user
class AccountView(LoginRequiredMixin,View):
    login_url = reverse_lazy('login') 

    @method_decorator(csrf_exempt)
    def dispatch(self, *args, **kwargs):
        return super().dispatch(*args, **kwargs)
    #It filters the procurements related to the logged in user.
    def get(self, request, *args, **kwargs):
       #Checkes the logged in user
        user = request.user
        
        user_reg = UserReg.objects.get(user=request.user)
        roles = user_reg.role.all()
        role_names = request.session.get('active_role')
        # Only logged in user can access this account page or else it redirects to the specific dashboard based on their role
        if "Accounts" in role_names:
            request.session["last_url"] = request.path
        elif "Recommending Authority" in role_names:
            return redirect('ra_dashboard')
        elif "Indentor" in role_names:
            return redirect('indentor_dashboard')
        elif "IMM" in role_names or "Purchase Assistant" in role_names:
            return redirect('imm_dashboard')
        elif "Approving Authority" in role_names:
            return redirect('aa_dashboard')
        else:
            return redirect(request.session.get("last_url", "/"))

        if user.is_authenticated:
            name = user.first_name
 
            department = UserReg.objects.get(user=user).user_dept
            mydep = UserReg.objects.get(user=user).user_dept.id
        else:
            name = 'Guest'  
            department = 'N/A'  
            mydep = 'N/A'
        #print("mydep",mydep)
        try:
            # Get procurement IDs from multiple stages
            immpr = pd.DataFrame(
                StageProgress.objects.filter(
                    Q(stagename__stage="stage3", remarktype__in=["Approval", "Modified"]) |
                    Q(stagename__stage="stage9", remarktype="DPO") |
                    Q(stagename__stage="stage1", remarktype__in=["PR_Raised", "Modified"])
                ).values("procurement_id__procurement_id")
            ).drop_duplicates(subset=["procurement_id__procurement_id"])["procurement_id__procurement_id"].to_list()

            # Get procurements assigned to the current user
            procurements_qs = Procurement.objects.filter(
                account_user=request.user,
                procurement_id__in=immpr,
                is_draft=False
            ).annotate(
                latest_valid_stage_datetime=Max(
                    'prid__datetime',
                    filter=Q(
                        prid__stagename__stage='stage3',
                        prid__remarktype__in=['Approval', 'Modified']
                    ) | Q(
                        prid__stagename__stage='stage9',
                        prid__remarktype='DPO'
                    ) | Q(
                        prid__stagename__stage='stage1',
                        prid__remarktype__in=['PR_Raised', 'Modified']
                    )
                )
            ).order_by('-latest_valid_stage_datetime', '-id')

            # Get query parameters
            start_date_str = request.GET.get("startDate")
            end_date_str = request.GET.get("endDate")
            status_filter = request.GET.get("statusFilter")

            #print("start_date_str:", start_date_str)
            #print("end_date_str:", end_date_str)
            #print("status_filter:", status_filter)

            # Date filtering logic
            try:
                today = datetime.today().date()

                if start_date_str:
                    try:
                        start_date = datetime.strptime(start_date_str, "%Y-%m-%d").date()
                    except ValueError:
                        start_date = None
                else:
                    start_date = None

                if end_date_str:
                    try:
                        end_date = datetime.strptime(end_date_str, "%Y-%m-%d").date()
                    except ValueError:
                        end_date = None
                else:
                    end_date = None

                # Apply date filtering logic
                if start_date and end_date:
                    procurements_qs = procurements_qs.filter(datetime__date__gte=start_date, datetime__date__lte=end_date)
                elif start_date and not end_date:
                    procurements_qs = procurements_qs.filter(datetime__date__gte=start_date, datetime__date__lte=today)
                elif not start_date and end_date:
                    procurements_qs = procurements_qs.filter(datetime__date__lte=end_date)
                elif not start_date and not end_date:
                    # Default: current + previous month
                    first_day_current_month = today.replace(day=1)
                    first_day_previous_month = first_day_current_month - relativedelta(months=1)
                    procurements_qs = procurements_qs.filter(datetime__date__gte=first_day_previous_month)
            except Exception as e:
                print("Date filtering error:", e)

            status_list = []
            users = []

            for procurement in procurements_qs:
                pr_users = [proc.user.id for proc in procurements_qs if proc.user]
                #print("Procurement raiser user IDs:", pr_users)

                procurement.procurement_title = procurement.procurement_title

                # Fetch users related to "Approving Authority" role in the same department
                users = UserReg.objects.filter(
                    role__role="Approving Authority",
                    user_dept=procurement.user.userreg.user_dept,
                    is_active=True
                ).exclude(user=procurement.user).values(
                    "emp_id", "user__id", "user__first_name", "user__last_name", "user_dept__dept_name"
                )

                #print("Approving Authorities in department (after exclusion):", list(users))

                user_list = [
                    {
                        "emp_id": user["emp_id"],
                        "full_name": f"{user['user__first_name']} {user['user__last_name']}"
                    } for user in users
                ]

                # Get user roles
                user_roles = list(UserReg.objects.filter(user=procurement.user).values_list("role__role", flat=True))

                # Fetch latest stage progress
                checkmsg = StageProgress.objects.filter(
                    procurement_id__procurement_id=procurement.procurement_id
                ).values("stagename__stage", "remarktype").last()

                procurement.action_performed = False  # default

                if checkmsg:
                    stage = checkmsg["stagename__stage"]
                    remark = checkmsg["remarktype"]

                    # Check if user has both "Indentor" and "IMM" roles
                    has_indentor_imm = "Indentor" in user_roles and "IMM" in user_roles

                    if has_indentor_imm:
                        # Broader condition for dual-role user
                        if (
                            (stage == "stage3" and remark in ["Approval", "Modified"]) or 
                            (stage == "stage1" and remark in ["PR_Raised", "Modified"])
                        ):
                            procurement.action_performed = True
                    else:
                        # Narrower condition for all other users
                        if (
                            (stage == "stage3" and remark in ["Approval", "Modified"])
                        ):
                            procurement.action_performed = True

                # Get all remarks/stages for the procurement
                remarks = set()

                # ✅ Reject
                reject_remarks = StageProgress.objects.filter(
                    procurement_id__procurement_id=procurement.procurement_id,
                    remarktype="Reject"
                ).values_list("remarktype", flat=True).distinct()
                remarks.update(reject_remarks)

                # ✅ Modified
                modified_remarks = StageProgress.objects.filter(
                    procurement_id__procurement_id=procurement.procurement_id,
                    remarktype="Modified"
                ).values_list("remarktype", flat=True).distinct()
                remarks.update(modified_remarks)

                # ✅ Stage 5 Approval (latest only)
                latest_stage5 = (
                    StageProgress.objects.filter(
                        procurement_id__procurement_id=procurement.procurement_id,
                        stagename__stage="stage5"
                    )
                    .order_by("-datetime")
                    .values_list("remarktype", flat=True)
                    .first()
                )
                if latest_stage5 == "Approval":
                    remarks.add("Approval")


                status_list.append({
                    "procurement_id": procurement.procurement_id,
                    "statuses": list(remarks)
                })

            # If any exception occurs, reset the lists
        except Exception as e:
            #print(f"Error in get_procurement_data: {e}")
            procurements_qs = []
            status_list = []
            users = []

        # ⭐ Stable ordering for PostgreSQL + SQLite
        # Proper ordering: latest stage → latest PR datetime → latest ID
        
        # Latest Stage FIRST → then ID

        # But still keep ID sorting correct, use:
        # procurements_qs = sorted(
        #     procurements_qs,
        #     key=lambda p: (
        #         p.latest_valid_stage_datetime or datetime.min,
        #         p.id
        #     ),
        #     reverse=True
        # )
        #Correct sorting (ID first, then stage)
        procurements_qs = sorted(
            procurements_qs,
            key=lambda p: (
                p.latest_valid_stage_datetime or p.datetime or datetime.min
            ),
            reverse=True
        )

        # Return data to frontend (rendering)
        return render(request, 'ims/accounts.html', {
            'procurements': procurements_qs,
            'status_list': status_list,
            'user': users,
        })

