class TrackingView(LoginRequiredMixin, TemplateView):
    login_url = reverse_lazy('login')
    template_name = 'ims/tracking.html'
 
    @method_decorator(csrf_exempt)
    def dispatch(self, *args, **kwargs):
        return super().dispatch(*args, **kwargs)
 
    def get_emp_id(self, user):
        if user and hasattr(user, 'userreg'):
            return user.userreg.emp_id
        return 'N/A'
    def get_emp_role(self, user):
        if user and hasattr(user, 'userreg'):
            roles = user.userreg.role.all()
            if roles.count() >= 2:
                non_indentor_roles = roles.exclude(role='Indentor')
                if non_indentor_roles.exists():
                    return non_indentor_roles.first().role
                else:
                    return roles.first().role
            else:
                return roles.first().role
        return 'N/A'
 
    def _user_data(self, user):
        """Helper to return name and emp_id dict for a user (or fallback)."""
        return {
            'name': user.get_full_name() if user else 'N/A',
            'emp_id': self.get_emp_id(user) if user else 'N/A'
        }
 
    def get_context_data(self, **kwargs):
        context = super().get_context_data(**kwargs)
        user = self.request.user
        active_role = self.request.session.get('active_role', None)
        user_roles = get_all_roles_for_user(user)
 
        role_to_field_map = {
            'Indentor': 'user',
            'Recommending Authority': 'ra_user',
            'Purchase Assistant': 'imm_user',
            'IMM': 'imm_user',
            'Accounts': 'account_user',
            'Approving Authority': 'aa_user',
        }
 
        procurements = Procurement.objects.filter(is_draft=False, modificationpr=False)
 
        if active_role in role_to_field_map:
            field_name = role_to_field_map[active_role]
            procurements = procurements.filter(**{field_name: user})
 
        procurements = procurements.order_by('-datetime')
 
        # Date filtering (your existing code remains the same)
        start_date_str = self.request.GET.get("startDate")
        end_date_str = self.request.GET.get("endDate")
        today = datetime.today().date()
        start_date, end_date = None, None
 
        try:
            if start_date_str:
                start_date = datetime.strptime(start_date_str, "%Y-%m-%d").date()
            if end_date_str:
                end_date = datetime.strptime(end_date_str, "%Y-%m-%d").date()
 
            if start_date and end_date:
                procurements = procurements.filter(datetime__date__gte=start_date, datetime__date__lte=end_date)
            elif start_date:
                procurements = procurements.filter(datetime__date__gte=start_date, datetime__date__lte=today)
            elif end_date:
                procurements = procurements.filter(datetime__date__lte=end_date)
            else:
                first_day_current_month = today.replace(day=1)
                first_day_previous_month = first_day_current_month - relativedelta(months=1)
                procurements = procurements.filter(datetime__date__gte=first_day_previous_month)
        except Exception as e:
            print("Date filtering error:", e)
 
        processed_procurements = []
        ist = pytz.timezone('Asia/Kolkata')
       
        for procurement in procurements.prefetch_related('particular', 'particular__datequantity'):
            created_datetime = procurement.datetime.astimezone(ist).strftime('%d-%m-%Y %H:%M:%S')
 
            stages_with_status = {
                "procurement": [],
                "particulars": {},
                "vendors": {}
            }
 
            all_stage_entries = StageProgress.objects.filter(
                procurement_id=procurement.id
            ).order_by('datetime')
 
            first_stage8_entry = StageProgress.objects.filter(
                procurement_id=procurement.id,
                stagename__stage='stage8'
            ).order_by('datetime').first()
 
            dpo_entry_time = StageProgress.objects.filter(
                procurement_id=procurement.id,
                stagename__stage='stage9'
            ).order_by('datetime').first()
 
            # --- Preload Related DPOs, POs, and POApprovals ---
            related_dpos = DPO.objects.filter(procurement=procurement).select_related('sources')
            vendor_map = {dpo.sources.id: dpo for dpo in related_dpos}
 
            related_pos = Purchase_Order.objects.filter(procurement=procurement).select_related('draft_po__sources')
            po_map = {po.draft_po.sources.id: po for po in related_pos if po.draft_po and po.draft_po.sources}
 
            related_po_approvals = POApproval.objects.filter(po__in=related_pos).select_related('po', 'user')
            po_approval_map = {}
            for approval in related_po_approvals:
                po_approval_map.setdefault(approval.po.id, []).append(approval)
           
            # --- Process Each Stage Entry ---
            for entry in all_stage_entries:
                dt = entry.datetime.astimezone(ist).strftime('%d-%m-%Y %H:%M:%S')
                action_user = entry.rejectuser if entry.remarktype.lower() == 'reject' else entry.user
                action_type = 'reject' if entry.remarktype.lower() == 'reject' else 'action'
   
                stage_data = {
                    'stage': entry.stagename.stage,
                    'status': entry.remarktype.lower(),
                    'datetime': dt,
                    'comment': entry.remarks or '',
                    'procurement_id': procurement.procurement_id,
                    'action_user': {
                        'name': action_user.get_full_name() if action_user else 'N/A',
                        'emp_id': self.get_emp_id(action_user),
                        'role': self.get_emp_role(action_user),
                    } if action_user else 'N/A',
                    'action_type': action_type
                }
 
                # Handle forwarded_to
                if entry.forwarded_to:
                    stage_data['forwarded_to'] = {
                        'name': entry.forwarded_to.get_full_name() if entry.forwarded_to else 'N/A',
                        'emp_id': self.get_emp_id(entry.forwarded_to),
                        'role': self.get_emp_role(entry.forwarded_to),
                        'status': 'pending'
                    }
 
                # Handle reject cases
                if entry.remarktype.lower() == 'reject':
                    stage_data['rejected_to'] = {
                        'name': entry.rejectuser.get_full_name() if entry.rejectuser else 'N/A',
                        'emp_id': self.get_emp_id(entry.rejectuser),
                        'role': self.get_emp_role(entry.rejectuser),
                        'status': 'rejected'
                    }
 
                # --- CASE 1: Stage 9 (DPO / DPO Approval) ---
                if entry.stagename.stage == 'stage9':
                    if entry.vendors:
                        vendor = entry.vendors
                        dpo = vendor_map.get(vendor.id)
                        if dpo:
                            stages_with_status["vendors"].setdefault(vendor.id, [])
                            vendor_stage_data = stage_data.copy()
                            vendor_stage_data['vendor_id'] = vendor.id
                            vendor_stage_data['vendor_name'] = vendor.company_name1 or ''
                            vendor_stage_data['dpo_id'] = dpo.dpoid or dpo.id
                            vendor_stage_data['stage_label'] = "DPO Approval"
                            vendor_stage_data['particulars'] = list(
                                dpo.particular.values_list(
                                    'quotation_particular__csparticular__item_name', flat=True
                                )
                            )
                            stages_with_status["vendors"][vendor.id].append(vendor_stage_data)
                    continue
 
                # --- CASE 2: Stage 10 (PO Creation + Approval) ---
                if entry.stagename.stage == 'stage10':
                    if entry.vendors:
                        vendor = entry.vendors
                        po = po_map.get(vendor.id)
                        if po:
                            stages_with_status["vendors"].setdefault(vendor.id, [])
                            po_stage_data = stage_data.copy()
                            po_stage_data['vendor_id'] = vendor.id
                            po_stage_data['vendor_name'] = vendor.company_name1 or ''
                            po_stage_data['po_id'] = po.id
                            po_stage_data['po_number'] = po.po_number or ''
                            po_stage_data['po_grandtotal'] = float(po.po_grandtotal or 0)
                            po_stage_data['po_file'] = po.po_files.url if po.po_files else ''
                            po_stage_data['stage_label'] = "Purchase Order (Stage 10)"
                            stages_with_status["vendors"][vendor.id].append(po_stage_data)
 
                            if po_approval_map.get(po.id):
                                for approval in po_approval_map[po.id]:
                                    approval_data = {
                                        'stage': 'po_approval',
                                        'status': 'approved' if approval.done_sign else 'pending',
                                        'datetime': approval.po_approval.datetime.astimezone(ist).strftime('%d-%m-%Y %H:%M:%S'),
                                        'comment': approval.remarks or '',
                                        'procurement_id': procurement.procurement_id,
                                        'action_user': {
                                            'name': approval.user.get_full_name() if approval.user else 'N/A',
                                            'emp_id': self.get_emp_id(approval.user),
                                            'role': self.get_emp_role(approval.user),
                                        } if approval.user else 'N/A',
                                        'vendor_id': vendor.id,
                                        'vendor_name': vendor.company_name1 or '',
                                        'po_number': po.po_number or '',
                                        'stage_label': 'PO Approval'
                                    }
                                    stages_with_status["vendors"][vendor.id].append(approval_data)
                    continue
 
                # --- CASE 3: Negotiation (Stage 8) ---
                if entry.nego_quota_particular:
                    particular = entry.nego_quota_particular.quoted_vendors.csparticular
                    stage_data['particular_id'] = particular.id
                    stage_data['vendor_id'] = entry.nego_quota_particular.vendors.id if entry.nego_quota_particular.vendors else None
                    stage_data['vendor_name'] = entry.nego_quota_particular.vendors.company_name1 if entry.nego_quota_particular.vendors else None
                    stage_data['item_name'] = particular.item_name
                    # stages_with_status["particulars"][particular.id].append(stage_data)
                    stages_with_status["particulars"].setdefault(particular.id, []).append(stage_data)
 
                    continue
 
                # --- CASE 4: Post-DPO Entries (Stages after DPO approval) ---
                if related_dpos.exists():
                    last_dpo_time = related_dpos.aggregate(last_time=models.Max('date'))['last_time']
                    if entry.datetime >= last_dpo_time:
                        if entry.vendors:
                            vendor = entry.vendors
                            dpo = vendor_map.get(vendor.id)
                            if dpo:
                                stages_with_status["vendors"].setdefault(vendor.id, [])
                                vendor_stage_data = stage_data.copy()
                                vendor_stage_data['vendor_id'] = vendor.id
                                vendor_stage_data['vendor_name'] = vendor.company_name1 or ''
                                vendor_stage_data['dpo_id'] = dpo.dpoid or dpo.id
                                vendor_stage_data['stage_label'] = "Post DPO Stage"
 
                                particulars_data = []
                                for particular in dpo.particular.all():
                                    particulars_data.append({
                                        'id': particular.id,
                                        'name': particular.quotation_particular.csparticular.item_name
                                        if particular.quotation_particular and particular.quotation_particular.csparticular else ''
                                    })
 
                                vendor_stage_data['particulars'] = particulars_data
                                stages_with_status["vendors"][vendor.id].append(vendor_stage_data)
                        continue
 
                # --- CASE 5: Pre-DPO Regular Stages ---
                # ###################pdb.set_trace
                # --- CASE 5: Pre-DPO Regular Stages ---
                if first_stage8_entry and entry.datetime >= first_stage8_entry.datetime:
 
                    # 🚫 Prevent Stage >= DPO time from going into particulars
                    if dpo_entry_time and entry.datetime >= dpo_entry_time.datetime:
                        vendor_id = entry.vendors.id if entry.vendors else 'unknown_vendor'
                        stages_with_status["vendors"].setdefault(vendor_id, []).append(stage_data)
                        continue
 
                    assigned_to_particular = False
                    for part in procurement.particular.all():
 
                        particular_stage8 = StageProgress.objects.filter(
                            procurement_id=procurement.id,
                            stagename__stage='stage8',
                            nego_quota_particular__quoted_vendors__csparticular=part
                        ).order_by('datetime').first()
 
                        # Assign to particular only if entry time >= that particular’s stage8
                        if particular_stage8 and entry.datetime >= particular_stage8.datetime:
                            stage_data['particular_id'] = part.id
                            stage_data['item_name'] = part.item_name
                            stages_with_status["particulars"].setdefault(part.id, []).append(stage_data)
                            assigned_to_particular = True
                            break
 
                    # If not matched to any particular → push to vendors bucket
                    if not assigned_to_particular:
                        vendor_id = entry.vendors.id if entry.vendors else 'unknown_vendor'
                        stages_with_status["vendors"].setdefault(vendor_id, []).append(stage_data)
 
                    continue
 
 
                # --- POST-DPO ENTRY (Non-Stage8) ---
                elif dpo_entry_time and entry.datetime >= dpo_entry_time.datetime:
                    vendor_id = entry.vendors.id if entry.vendors else 'unknown_vendor'
                    stages_with_status["vendors"].setdefault(vendor_id, []).append(stage_data)
 
 
                # --- PRE-STAGE8 NORMAL STAGES ---
                else:
                    stages_with_status["procurement"].append(stage_data)
 
 
            #print(stages_with_status)
 
            # --- Add Pending / Reject Logic in Correct Group ---
            try:
                all_entries, group_tracker = [], []
 
                for entry in stages_with_status.get("procurement", []):
                    all_entries.append(entry)
                    group_tracker.append(("procurement", None))
                for pid, plist in stages_with_status.get("particulars", {}).items():
                    for entry in plist:
                        all_entries.append(entry)
                        group_tracker.append(("particulars", pid))
                for vid, vlist in stages_with_status.get("vendors", {}).items():
                    for entry in vlist:
                        all_entries.append(entry)
                        group_tracker.append(("vendors", vid))
 
                if all_entries:
                    all_entries_sorted = sorted(zip(all_entries, group_tracker), key=lambda x: x[0]['datetime'])
                    last_entry, (last_group, last_key) = all_entries_sorted[-1]
 
                    last_status = last_entry.get('status', '').lower()
                    last_datetime = last_entry.get('datetime')
 
                    print('PR', procurement.procurement_id, 'last status', last_status, 'last datetime', last_datetime, 'last stage', last_entry.get('stage', ''))
                   
                    entry_query = StageProgress.objects.filter(procurement_id=procurement.id,
                                                        remarktype__iexact=last_status).order_by('-datetime').first()
                    # Reject → pending for reject user
                    if last_status in ('reject', 'returned','dpo_return'):
                        if entry_query and entry_query.rejectstage:
                            user = entry_query.rejectuser
                            pending_entry = {
                                'stage': entry_query.rejectstage.stage,
                                'status': 'pending',
                                'datetime': last_datetime,
                                'comment': '',
                                'next_user': {
                                    'name': user.get_full_name() if user else 'N/A',
                                    'emp_id': self.get_emp_id(user),
                                    'role': self.get_emp_role(user)
                                }
                            }
                            if last_group == "procurement":
                                stages_with_status["procurement"].append(pending_entry)
                            elif last_group == "particulars":
                                stages_with_status["particulars"].setdefault(last_key, []).append(pending_entry)
                            elif last_group == "vendors":
                                stages_with_status["vendors"].setdefault(last_key, []).append(pending_entry)
 
                    # Forwarded → pending for next user
                    else:
                        if entry_query and entry_query.forwarded_to:
                            user = entry_query.forwarded_to
                            user_role = self.get_emp_role(user)
                            pending_entry = {
                                'stage': "",
                                'status': 'pending',
                                'datetime': last_datetime,
                                'comment': '',
 
                                'next_user': {
                                    'name': user.get_full_name() if user else 'N/A',
                                    'emp_id': self.get_emp_id(user),
                                    'role': user_role
                                }
                            }
                            if last_group == "procurement":
                                stages_with_status["procurement"].append(pending_entry)
                            elif last_group == "particulars":
                                stages_with_status["particulars"].setdefault(last_key, []).append(pending_entry)
                            elif last_group == "vendors":
                                stages_with_status["vendors"].setdefault(last_key, []).append(pending_entry)
            except Exception as e:
                print("⚠️ Pending/Reject logic error:", e)
 
            processed_procurements.append({
                'procurement_id': procurement.procurement_id,
                'procurement_title': procurement.procurement_title,
                'created_datetime': created_datetime,
                'stages_with_status': stages_with_status,
                'users': {
                    'user': self._user_data(procurement.user),
                    'ra_user': self._user_data(procurement.ra_user),
                    'imm_user': self._user_data(procurement.imm_user),
                    'account_user': self._user_data(procurement.account_user),
                    'aa_user': self._user_data(procurement.aa_user),
                }
            })
 
        #print(processed_procurements, "processed_procurements")
        context['procurements'] = processed_procurements
        return context
 
 
 


        
