def get_current_financial_year():   

    """Returns the current financial year as a string, e.g., '2024-2025'."""
    today = date.today()
    if today.month >= 4:
        return f"{today.year}-{today.year + 1}"
    else:
        return f"{today.year - 1}-{today.year}"


@csrf_exempt

def get_financial_year_range(financial_year_str):
    start_year, end_year = map(int, financial_year_str.split('-'))
    return {
        "start": f"{start_year}-04-01",
        "end": f"{end_year}-03-31"
    }
def get_financial_year_for_date(input_date):
    if input_date.month >= 4:
        return f"{input_date.year}-{input_date.year + 1}"
    else:
        return f"{input_date.year - 1}-{input_date.year}"


def get_next_particular_id(procurement):
    """
    Generate the next particular_id for a given procurement,
    checking both the original procurement and all modified PRs.
    Format: <procurement_id>-XX
    """
    procurement_id = procurement.procurement_id

    # Get the last particular of the original procurement
    last_particular = procurement.particular.order_by('-id').first()

    max_serial = 0
    if last_particular and last_particular.particular_id.startswith(procurement_id):
        try:
            max_serial = int(last_particular.particular_id.split('-')[-1])
        except ValueError:
            max_serial = 0

    # Collect particulars linked to modified PRs if needed
    modified_prs = ModifiedPr.objects.filter(procurement=procurement)
    for mpr in modified_prs:
        if mpr.modifiedpr:
            last_modified = mpr.modifiedpr.particular.order_by('-id').first()
            if last_modified and last_modified.particular_id.startswith(procurement_id):
                try:
                    serial = int(last_modified.particular_id.split('-')[-1])
                    if serial > max_serial:
                        max_serial = serial
                except ValueError:
                    continue

    # New serial number
    new_serial = max_serial + 1
    return f"{procurement_id}-{new_serial:02d}"




