            if not selected_user_id:
                return JsonResponse({"status": "error", "message": "No user selected"}, status=400)

            try:
                selected_user_reg = UserReg.objects.get(emp_id=selected_user_id)  
                selected_user = selected_user_reg.user 
            except UserReg.DoesNotExist:
                return JsonResponse({"status": "error", "message": "User does not exist"}, status=400)
            #Attachments will be sent from the frontend
            attachment = request.FILES.get('attachment')
            #print("FILES RECEIVED:", request.FILES)
            #saves the stageprogress data related to the rejection process
            stage_progress = StageProgress.objects.create(
                procurement_id=procurement,
                stagename=Stages.objects.get(stage="stage2"),  
                remarktype='Reject',
                remarks=remarks,
                attachment=attachment,
                user=request.user,
                rejectstage=Stages.objects.get(stage=request.POST.get('rejectstage')),
                rejectuser=selected_user  
            )
            #Stage datetime saving
            stage_datetime = stage_progress.datetime  # This is in UTC by default
            ist_timezone = pytz.timezone('Asia/Kolkata')
            stage_datetime_ist = stage_datetime.astimezone(ist_timezone)  # Convert UTC to IST
            formatted_stage_datetime = stage_datetime_ist.strftime("%Y-%m-%d %H:%M:%S")   
            #Tracking Details
            Tracking.objects.get(procurement_id=procurement).tracker.add(stage_progress)
            Tracking.objects.get(procurement_id=procurement).progress.remove(Stages.objects.get(stage=request.POST.get('rejectstage')))
            Tracking.objects.get(procurement_id=procurement).progress.add(Stages.objects.get(stage="stage4"))
            #Sends the stageprogress data to frontend immediate after the rejection process of procurement
            stage_progress = pd.DataFrame(StageProgress.objects.filter(id=stage_progress.id).values("procurement_id","datetime", "remarktype", "remarks",  "user__username", "user__first_name","stagename__stage", "user__userreg__user_dept__dept_name","attachment","rejectuser__username","rejectuser__first_name","forwarded_to__username","forwarded_to__first_name","user__last_name",)).to_dict('records')

            return JsonResponse({
                'status': 'success',
                'message': 'Procurement successfully returned to Stage ',
                'stage_datetime': formatted_stage_datetime,
                'stage_list': stage_progress,
                 'stagecount':StageProgress.objects.filter(procurement_id=procurement).exclude(
                        # Q(stagename__stage='stage8', remarktype="Negotiation")
                    ).count()
            })
