#View related to the Procurements which are submitted for the specific user

class SubmittedPr(LoginRequiredMixin, View):
    login_url = reverse_lazy('login') 

    @method_decorator(csrf_exempt)
    def dispatch(self, *args, **kwargs):
        return super().dispatch(*args, **kwargs)
    #Get condition related to the procurements for the specific user based on the stages data 
    def get(self, request):
        user = request.user

        try:
            # ##pdb
            user_reg = UserReg.objects.get(user=user)
            roles = user_reg.role.all()
            role_names = request.session.get('active_role')

            # Role-based redirection
            if "Indentor" in role_names:
                request.session["last_url"] = request.path
            elif "Accounts" in role_names:
                return redirect('acc_dashboard')
            elif "Recommending Authority" in role_names:
                return redirect('ra_dashboard')
            elif "IMM" in role_names or "Purchase Assistant" in role_names:
                return redirect('imm_dashboard')
            elif "Approving Authority" in role_names:
                return redirect('aa_dashboard')
            else:
                return redirect(request.session.get("last_url", "/"))

            # Fetch data using helper
            data = get_indentor_procurement_subdata(request,user)

        except Exception as e:
            #print("Error in SubmittedPr view:", e)
            data = {
                "procurements": [],
                "status_list": []
            }

        return render(request, 'ims/submittedpr.html', data)
    
    
    #Post call related to the specific procurement like click function,and the procurements,particulars data sends to frontend 
