class FeedbackView(TemplateView):
    template_name = 'ims/feedback.html'

    def get_context_data(self, **kwargs):
        context = super().get_context_data(**kwargs)
        context['feedbacks'] = UserFeedback.objects.all().order_by('-created_at')
        return context
    def post(self, request, *args, **kwargs):
            if not request.user.is_authenticated:
                return JsonResponse({'status': 'error', 'message': 'Authentication required'}, status=403)

            try:
                data = json.loads(request.body)

                # ✅ Get UserReg linked to the current Django User
                user_reg = UserReg.objects.get(user=request.user)

                feedback = UserFeedback.objects.create(
                    user=user_reg,  # ✅ Correct: assign UserReg instance
                    
                    description=data.get('description')
                )

                return JsonResponse({
                    'status': 'success',
                    'feedback': {
                        'id': feedback.id,
                        'user_full_name': f"{user_reg.emp_id} - {request.user.first_name} {request.user.last_name}",
                        # 'title': feedback.title,
                        'description': feedback.description,
                        'created_at': feedback.created_at.strftime("%b %d, %Y %H:%M")
                    }
                })


            except UserReg.DoesNotExist:
                return JsonResponse({'status': 'error', 'message': 'User profile not found'}, status=404)
            except Exception as e:
                return JsonResponse({'status': 'error', 'message': str(e)}, status=400)

