                    # ---------------------------------------
                    stage8_status = {
                        'stage8_negotiation_datetime': stage8_negotiation_entry.datetime if stage8_negotiation_entry else None,
                        'stage4_after_8': stage4_after_8,
                        'stage9_after_8': stage9_after_8,
                    }


                    vendor_id = request.POST.get(f'vendor_id_{index}')  # if passed
                    vendor = Vendor.objects.get(id=vendor_id) if vendor_id else procurement.supplier.first()

