def user_has_vendor(vendor_id):
    return StageProgress.objects.filter(vendors__code=vendor_id).exists()


from decimal import Decimal, ROUND_HALF_UP
def get_financial_year(date):
    """
    Returns financial year string like '2025-2026' for a given date.
    Financial year starts on April 1st.
    """
    year = date.year
    if date.month < 4:
        return f"{year - 1}-{year}"
    else:
        return f"{year}-{year + 1}" 

