                Tracking.objects.get(procurement_id=procurement).progress.add(Stages.objects.get(stage="stage9"))
                stage_progress = pd.DataFrame(StageProgress.objects.filter(id=stage_progress.id).values("procurement_id","datetime", "remarktype", "remarks",  "user__username", "user__first_name","stagename__stage", "user__userreg__user_dept__dept_name","attachment","rejectuser__username","rejectuser__first_name","forwarded_to__username","forwarded_to__first_name","user__last_name")).to_dict('records')

