# Function to generate 10 financial years from now
def generate_financial_years():
    current_year = datetime.now().year
    return [f"{y}-{y+1}" for y in range(current_year, current_year + 10)]
class BudgetAllocationView(LoginRequiredMixin,View):
    login_url = reverse_lazy('login')
 
    @method_decorator(csrf_exempt)
    def dispatch(self, *args, **kwargs):
        return super().dispatch(*args, **kwargs)
    """
    GET: Renders a form with existing projects, financial years, and budget allocations.
    POST: Handles creation or update of budget allocations for a project and logs the changes.
    """
   
    template_name = "ims/budget_allocation.html"
 
    def get_common_context(self):
        """
        Prepares context data used by both GET and POST requests:
        - List of all projects.
        - List of financial years (current + next 10 years).
        - Current budget allocations (with project and year details).
        """
        # ##pdb
        projects = Project.objects.all()
        financial_years = generate_financial_years()
        allocations_qs = BudgetAllocation.objects.select_related('project').all()
 
        # Prepare allocation data with selected fields
        allocations = list(
            allocations_qs.values(
                'project__project_id', 'project__name', 'financial_year',
                'allocated_budget', 'remaining_budget'
            )
        )
 
        #print(allocations)
 
        return {
            "projects": projects,
            "financial_years": financial_years,
            "allocations": allocations,
        }
 
    def get(self, request):
        """
       
        Renders the budget allocation form with context data.
        """
        user=request.user
        user_reg = UserReg.objects.get(user=request.user)
        roles = user_reg.role.all()
        role_names = request.session.get('active_role')
        # if not request.user.is_superuser:
        #     return redirect('login')
        if "Accounts" in role_names:
            request.session["last_url"] = request.path
        elif "IMM" in role_names or "Purchase Assistant" in role_names:
            return redirect('imm_dashboard')
        elif "Indentor" in role_names:
            return redirect('indentor_dashboard')
        elif "Recommending Authority" in role_names:
            return redirect('ra_dashboard')
        elif "Approving Authority" in role_names:
            return redirect('aa_dashboard')
        else:
            return redirect(request.session.get("last_url", "/"))
        return render(request, self.template_name, self.get_common_context())
 
    def post(self, request):
        """
        Handles form submission to:
        - Update an existing budget allocation, or
        - Create a new allocation if none exists.
        Includes validations and logging of changes.
        """
        context = self.get_common_context()
       
        # Extract form data
        # pdb.set_trace()
        project_id = request.POST.get("project")
        financial_year = request.POST.get("financial_year")
        remarks = request.POST.get("remarks")
        # ##pdb
 
        # Validate required fields
        if not (project_id and financial_year and remarks):
            context["error"] = "All fields are required."
            return render(request, self.template_name, context)
 
        # Retrieve the project or return 404
        project = get_object_or_404(Project, project_id=project_id)
 
        try:
            # Try to fetch existing allocation
            allocation = BudgetAllocation.objects.get(project=project, financial_year=financial_year)
 
            # Validate additional budget input
            allocation_increment_str = request.POST.get("additional_budget")
            if not allocation_increment_str or not allocation_increment_str.strip():
                context["error"] = "Additional budget is required for updating existing allocation."
                return render(request, self.template_name, context)
 
            try:
                allocation_increment = Decimal(allocation_increment_str)
            except InvalidOperation:
                context["error"] = "Invalid value for additional budget. Please enter a valid number."
                return render(request, self.template_name, context)
 
            # Prevent negative remaining budget
            if allocation.remaining_budget + allocation_increment < 0:
                context["error"] = "Additional budget cannot reduce remaining budget below 0."
                return render(request, self.template_name, context)
 
            # Store previous values for logging
            previous_allocated = allocation.allocated_budget
            previous_remaining = allocation.remaining_budget
 
            # Update allocation values
            allocation.allocated_budget += allocation_increment
            allocation.remaining_budget += allocation_increment
            allocation.save()
 
            # Log the update
            BudgetAllocationLog.objects.create(
                budget_allocation=allocation,
                previous_allocated=previous_allocated,
                previous_remaining=previous_remaining,
                updated_allocated=allocation.allocated_budget,
                updated_remaining_budget=allocation.remaining_budget,
                remarks=remarks,
            )
           
        # No existing allocation: create a new one
        except BudgetAllocation.DoesNotExist:
            allocated_budget_str = request.POST.get("allocated_budget")
            remaining_budget_str = request.POST.get("remaining_budget")
 
            # Validate input for new allocation
            if not (allocated_budget_str and remaining_budget_str):
                context["error"] = "Allocated and remaining budget are required for new allocations."
                return render(request, self.template_name, context)
 
            try:
                allocated_budget = Decimal(allocated_budget_str)
                remaining_budget = Decimal(remaining_budget_str)
                if allocated_budget <= 0 or remaining_budget < 0:
                    raise InvalidOperation("Budgets must be non-negative, and allocated must be > 0.")
            except (InvalidOperation, TypeError, ValueError):
                context["error"] = "Invalid budget values. Please enter valid numbers."
                return render(request, self.template_name, context)
 
            # Create new allocation
            allocation = BudgetAllocation.objects.create(
                project=project,
                financial_year=financial_year,
                allocated_budget=allocated_budget,
                remaining_budget=remaining_budget,
                budgettype="Project",
            )
 
            # Log the new allocation
            BudgetAllocationLog.objects.create(
                budget_allocation=allocation,
                previous_allocated=Decimal("0.00"),
                previous_remaining=Decimal("0.00"),
                updated_allocated=allocated_budget,
                updated_remaining_budget=remaining_budget,
                remarks=remarks,
            )
 
        # Redirect to the same view after successful save
        return redirect(reverse('budget_allocation_view'))
 
class BudgetLogsAPI(View):
 
    """
    API view that returns a JSON response containing the budget allocation
    change logs for a specific project.
    """
   
    def get(self, request, project_id):
       
        # Fetch logs related to the given project, including related project data ordered by latest updates first
        logs = BudgetAllocationLog.objects.filter(
            budget_allocation__project__project_id=project_id
        ).select_related(
            'budget_allocation__project'
        ).order_by('-updated_at')
 
        # list of log entries in a JSON format
        logs_list = [
            {
                "updated_at": localtime(log.updated_at).isoformat(),  # Human-readable timestamp
                "project": log.budget_allocation.project.name,  # Project name
                "financial_year": log.budget_allocation.financial_year,  # Financial year of the log
                "previous_allocated": str(log.previous_allocated),  # Budget before update
                "previous_remaining": str(log.previous_remaining),  # Remaining budget before update
                "updated_allocated": str(log.updated_allocated),  # New allocated budget
                "updated_remaining_budget": str(log.updated_remaining_budget),  # New remaining budget
                "remarks": log.remarks,  # Remarks provided during the update
            }
            for log in logs
        ]
 
        # Return the logs as a JSON response
        return JsonResponse({"logs": logs_list})
 
 
