class CalendarEvents(LoginRequiredMixin, View):
    """
    View for returning JSON event data for calendar visualization.
    Only accessible to logged-in users with Accounts, IMM, or CEO roles.
    Returns a list of all payment installments (PaymentTracking) with:
        - Installment date
        - Procurement/project details
        - Submitted by
        - Uploaded date
        - File names
    """

    login_url = reverse_lazy('login')

    @method_decorator(csrf_exempt)
    def dispatch(self, *args, **kwargs):
        # Disables CSRF check for this view (used for API-like behavior)
        return super().dispatch(*args, **kwargs)

    def get(self, request, *args, **kwargs):
        user = request.user
        user_reg = UserReg.objects.get(user=user)
        role_names = [role.role for role in user_reg.role.all()]

        # Allow only specific roles to access calendar data
        if "Accounts" or "IMM" or "CEO" in role_names:
            request.session["last_url"] = request.path
        elif "Recommending Authority" in role_names:
            return redirect('ra_dashboard')
        elif "Indentor" in role_names:
            return redirect('indentor_dashboard')
        elif "Approving Authority" in role_names:
            return redirect('aa_dashboard')
        else:
            return redirect(request.session.get("last_url", "/"))

        # Get all payment installments where procurement has a DPO
        installments = PaymentTracking.objects.filter(
            payment__procurement__draft_pos__dpoid__isnull=False
        ).select_related(
            'payment',
            'payment__procurement',
            'payment__procurement__project',
            'submitted_by'
        ).prefetch_related('invoice_file').distinct()

        results = []

        for inst in installments:
            if not inst.installment_date:
                continue  # Skip entries with no installment date

            procurement = inst.payment.procurement if inst.payment else None
            project = procurement.project if procurement else None

            # Join file names for display
            file_names = ', '.join([
                file.file_location.name.split('/')[-1]
                for file in inst.invoice_file.all()
            ]) if inst.invoice_file.exists() else " "

            results.append({
                'installment_date': inst.installment_date.isoformat(),  # For calendar event rendering
                'procurement_id': procurement.procurement_id if procurement else None,
                'project_name': project.name if project else None,
                'submitted_by': f"{inst.submitted_by.username} ({inst.submitted_by.emp_id})" if inst.submitted_by else " ",
                'amount': inst.payment_amount if inst.payment_amount else 0,
                'uploaded_date': inst.uploaded_date.strftime('%Y-%m-%d %H:%M') if inst.uploaded_date else " ",
                'file_name': file_names,
                'month': month_name[inst.installment_date.month],
                'year': inst.installment_date.year,
            })

        # Return list of event objects as JSON
        return JsonResponse(results, safe=False)

