class  InvoicePageView(LoginRequiredMixin, View):
    login_url = reverse_lazy('login')

    @method_decorator(csrf_exempt)
    def dispatch(self, *args, **kwargs):
        return super().dispatch(*args, **kwargs)
    def get(self, request):
        today = datetime.today().date()
        start_date_str = request.GET.get("startDate")
        end_date_str = request.GET.get("endDate")

        # Parse dates
        try:
            start_date = datetime.strptime(start_date_str, "%Y-%m-%d").date() if start_date_str else None
        except:
            start_date = None

        try:
            end_date = datetime.strptime(end_date_str, "%Y-%m-%d").date() if end_date_str else None
        except:
            end_date = None

        dpo_qs = DPO.objects.select_related('procurement')

        # Date filter
        if start_date and end_date:
            dpo_qs = dpo_qs.filter(date__date__range=(start_date, end_date))
        elif start_date:
            dpo_qs = dpo_qs.filter(date__date__gte=start_date)
        elif end_date:
            dpo_qs = dpo_qs.filter(date__date__lte=end_date)
        else:
            first_day_current_month = today.replace(day=1)
            first_day_previous_month = first_day_current_month - relativedelta(months=1)
            dpo_qs = dpo_qs.filter(date__date__gte=first_day_previous_month)

        # Collect procurement IDs from filtered DPOs
        procurement_ids = list(dpo_qs.values_list("procurement_id", flat=True))

        po_list = []
        added_po_ids = set()

        # Fetch ALL POs for filtered procurements
        po_qs = Purchase_Order.objects.filter(procurement_id__in=procurement_ids).select_related("procurement")

        for po in po_qs:
            procurement = po.procurement
            if not procurement:
                continue

            # CHECK: STAGE13 must be completed for this PO
            stage13_done = PaymentTracking.objects.filter(
                payment__po_id=po,
                payment_stage__stagename__stage="stage13"
            ).exists()

            if not stage13_done:
                continue  # ❌ Skip this PO if Stage13 not completed

            # Avoid duplicates
            if po.id in added_po_ids:
                continue

            added_po_ids.add(po.id)

            po_list.append({
                "poid": po.po_number,
                "procurement_id": procurement.procurement_id,
                "datetime": procurement.datetime,
                "procurement_title": procurement.procurement_title,
                "purchase_order_id": po.id,
                "po_number": po.po_number,
                "pr_events": procurement.pr_events,
            })
        # ##########pdb.set_trace

        # ------------------------------
        # New condition: Online orders with no POs/DPOs
        # ------------------------------
        online_procurements = Procurement.objects.filter(
            pr_events="Online_order"
        ).exclude(id__in=procurement_ids)  # Exclude already included procurements

        for procurement in online_procurements:
            # Check Stage5 completion
            stage5_done = StageProgress.objects.filter(
                procurement_id=procurement,
                stagename__stage="stage5",
                remarktype="Approval"
            ).exists()

            # Check Stage13 completion
            stage13_done = PaymentTracking.objects.filter(
                payment__procurement=procurement,
                payment_stage__stagename__stage="stage13"
            ).exists()

            if stage5_done and stage13_done:
                po_list.append({
                    "poid": None,
                    "procurement_id": procurement.procurement_id,
                    "datetime": procurement.datetime,
                    "procurement_title": procurement.procurement_title,
                    "purchase_order_id": None,
                    "po_number": None,
                    "pr_events": procurement.pr_events,
                    
                })

        return render(request, "ims/invoice.html", {"po_data": po_list})



