class DpoApprovalAA(LoginRequiredMixin,View):
    login_url = reverse_lazy('login') 

    @method_decorator(csrf_exempt)
    def dispatch(self, *args, **kwargs):
        return super().dispatch(*args, **kwargs)

   
    def get(self, request):
        try:
            user = request.user
            user_reg = UserReg.objects.get(user=user)
            roles = user_reg.role.all()
            role_names = request.session.get('active_role')

            if "Approving Authority" in role_names or "Purchase Assistant" in role_names:
                request.session["last_url"] = request.path
            elif "Accounts" in role_names:
                return redirect('acc_dashboard')
            elif "Recommending Authority" in role_names:
                return redirect('ra_dashboard')
            elif "Indentor" in role_names:
                return redirect('indentor_dashboard')
            elif "IMM" in role_names:
                return redirect('imm_dashboard')
            else:
                return redirect(request.session.get("last_url", "/"))
            ##pdb
            # ✅ Get procurements that have Stage 9 Approval with a vendor
            approved_stage9_ids = list(StageProgress.objects.filter(
                stagename__stage="stage4",
                remarktype="Approval",
                forwarded_to=user,
                vendors__isnull=False
            ).values_list("procurement_id__procurement_id", flat=True).distinct())

            #print("✅ Approved Stage 9 Procurement IDs (vendor-specific):", approved_stage9_ids)

            procurements = Procurement.objects.filter(procurement_id__in=approved_stage9_ids)
            start_date_str = request.GET.get("startDate")
            end_date_str = request.GET.get("endDate")
            status_filter = request.GET.get("statusFilter")
           
            if "aa_prids" in request.session and request.session["aa_prids"]:
                raw_prids = request.session["aa_prids"]
                print("raw_prids:", raw_prids)

                # ✅ REMOVE ONLY THIS SESSION KEY AFTER USING IT
                request.session.pop("aa_prids", None)

            else:
                print("ra_prids NOT found or empty")
                raw_prids = None

            #print("start_date_str:", start_date_str)
            #print("end_date_str:", end_date_str)
            #print("status_filter:", status_filter)

            try:
                today = datetime.today().date()

                # Parse start and end dates
                start_date = datetime.strptime(start_date_str, "%Y-%m-%d").date() if start_date_str else None
                end_date = datetime.strptime(end_date_str, "%Y-%m-%d").date() if end_date_str else None

                # Apply date filtering logic to procurements
                if raw_prids:
                    pr_only_list = []
                    pr_vendor_pairs = []
                    pr_part_pairs = []  # NEW: PR–Particular pairs

                    items = [x.strip() for x in raw_prids.split(",") if x.strip()]

                    # Categorize each item
                    for element in items:

                        # CASE B: Vendor pair (e.g., PR100-5)
                        if "-" in element:
                            pr_id, vendor_id = element.split("-")
                            pr_vendor_pairs.append({
                                "pr_id": pr_id.strip(),
                                "vendor_id": vendor_id.strip()
                            })
                            continue

                        # CASE C: PR only
                        pr_only_list.append(element.strip())

                    if pr_only_list and not pr_vendor_pairs:

                        procurements = procurements.filter(procurement_id__in=pr_only_list)

                    elif pr_vendor_pairs:
                        filtered_dpos = []

                        for pair in pr_vendor_pairs:
                            pr = pair["pr_id"]
                            vendor = pair["vendor_id"]

                            dpo = DPO.objects.filter(
                                procurement__procurement_id=pr,
                                sources__code=vendor
                            ).first()

                            if dpo:
                                filtered_dpos.append(dpo)
                        
                        if filtered_dpos:
                            valid_pr_ids = {dpo.procurement.procurement_id for dpo in filtered_dpos}
                            procurements = procurements.filter(procurement_id__in=valid_pr_ids)
                            request.vendor_filtered_dpos = filtered_dpos
                        else:
                            procurements = procurements.none()
                    else:
                        procurements = procurements.none()
    
                elif start_date and end_date:
                    procurements = procurements.filter(datetime__date__gte=start_date, datetime__date__lte=end_date)
                elif start_date and not end_date:
                    procurements = procurements.filter(datetime__date__gte=start_date, datetime__date__lte=today)
                elif not start_date and end_date:
                    procurements = procurements.filter(datetime__date__lte=end_date)
                elif not start_date and not end_date:
                    # Default: current + previous month
                    first_day_current_month = today.replace(day=1)
                    first_day_previous_month = first_day_current_month - relativedelta(months=1)
                    procurements = procurements.filter(datetime__date__gte=first_day_previous_month)

            except Exception as e:
                print("Date filtering error:", e)

            procurements = procurements.order_by('-datetime')
            users=[]
            # ✅ Filter procurements that have at least one vendor with DPO approval
            valid_procurements = []
            for procurement in procurements:
                has_approved_vendor = StageProgress.objects.filter(
                    procurement_id=procurement,
                    stagename__stage="stage4",
                    remarktype="Approval",
                    vendors__isnull=False
                ).exists()
                if has_approved_vendor:
                    #print(f"✅ Procurement {procurement.procurement_id} has at least one approved vendor.")
                    valid_procurements.append(procurement)

            procurements = valid_procurements

            return_proc_ids = []
            form_types = {}
            actions = {}
            

            for procurement in procurements:
                form_type = 'import' if (
                    procurement.import_indigenous and procurement.import_indigenous.source_code == "02"
                ) else 'indigenous'
                procurement.form_type = form_type
                form_types[procurement.procurement_id] = form_type

                checkmsg = StageProgress.objects.filter(
                    procurement_id__procurement_id=procurement.procurement_id
                ).values("stagename__stage", "remarktype", "datetime").last()

                if checkmsg:
                    stage = checkmsg["stagename__stage"]
                    remark = checkmsg["remarktype"]
                    #print(f"📌 Procurement {procurement.procurement_id} - Last Stage: {stage}, Remark: {remark}")
                    procurement.action_performed = (
                        (stage == "stage2" and remark in ["Approval", "Modified"]) or
                        (stage == "stage7" and remark == "CST") or
                        (stage == "stage1" and remark == "Approval") or
                        (stage == "stage4" and remark == "Approval") or
                        (stage == "stage5" and remark == "Reject") or
                        (stage == "stage4" and remark == "Approval")
                    )
                else:
                    procurement.action_performed = False

                actions[procurement.procurement_id] = procurement.action_performed

                try:
                    vendor_map = defaultdict(list)
                    item_ra_chosen = set()

                    csts = CompartiveStatementPR.objects.filter(pro_id=procurement)
                    for cst in csts:
                        vendor_details = VendorQuotationDetails.objects.filter(cst=cst)

                        for vd in vendor_details:
                            vendor_instance = vd.sources
                            vendor_id = vendor_instance.code or "Unknown ID"
                            vendor_name = f"{vendor_instance.source_code} - {vendor_instance.name}" if hasattr(vendor_instance, 'source_code') else str(vendor_instance)
                            vendor_key = (vendor_id, vendor_name)

                            # ✅ Check if DPO approval exists for this procurement and vendor
                            dpo_approved = StageProgress.objects.filter(
                                procurement_id=procurement,
                                stagename__stage="stage4",
                                remarktype="Approval",
                                vendors__id=vendor_instance.id
                            ).exists()

                            #print(f"🔍 Checking vendor {vendor_id} for procurement {procurement.procurement_id}: DPO Approved = {dpo_approved}")

                            if not dpo_approved:
                                continue

                            for qp in vd.particular.all():
                                item = qp.csparticular
                                item_name = getattr(item, 'item_name', 'Unknown Item')
                                chosen_status = None

                                if qp.ra_choosen_vendor:
                                    chosen_status = 'RA Chosen Vendor'
                                    item_ra_chosen.add(item_name)
                                elif qp.system_choosen_vendor and item_name not in item_ra_chosen:
                                    chosen_status = 'System Chosen Vendor'

                                if chosen_status:
                                    vendor_map[vendor_key].append({
                                        'item_name': item_name,
                                        'chosen_status': chosen_status
                                    })

                    procurement.vendor_groups = [
                        {
                            'vendor_id': vid,
                            'vendor_name': vname,
                            'items': items
                        }
                        for (vid, vname), items in vendor_map.items()
                    ]

                    #print(f"🧾 Final Vendor Groups for {procurement.procurement_id}:", procurement.vendor_groups)

                    users = UserReg.objects.filter(
                        role__role="IMM",
                        user_dept=procurement.user.userreg.user_dept,
                        is_active=True
                    ).exclude(user=procurement.user).values(
                        "emp_id", "user__id", "user__first_name", "user__last_name", "user_dept__dept_name"
                    )

                    #print("Approving Authorities in department (after exclusion):", list(users))

                    user_list = [
                        {
                            "emp_id": user["emp_id"],
                            "full_name": f"{user['user__first_name']} {user['user__last_name']}"
                        } for user in users
                    ]

                except Exception as e:
                    #print(f"❌ Error processing procurement {procurement.procurement_id}: {e}")
                    procurement.vendor_groups = []

        except Exception as e:
            #print("❌ Outer Error:", e)
            procurements = []
            form_types = {}
            actions = {}
            return_proc_ids = []
            users = []
        
        procurements = sorted(
            procurements,
            key=lambda p: p.datetime or datetime.min,
            reverse=True
        )

        return render(request, 'ims/DPOAAApproval.html', {
            'procurements': procurements,
            'form_types': json.dumps(form_types),
            'actions': actions,
            'return_proc_ids': return_proc_ids,
            'user': users,
        })

