                # ).values_list("user", flat=True)
 
                # if user.id not in forwarded_users:
                #     continue
                #import #pdb; ##pdb

                    # ✅ Step 2: check if at least one vendor is approved in stage10 (PO)
                    # vendors_in_po = StageProgress.objects.filter(
                    #     procurement_id=procurement,
                    #     stagename__stage="stage10",
                    #     remarktype="PO",
                    #     vendors__isnull=False
                    # ).values_list("vendors", flat=True).distinct()
    
                    # if not vendors_in_po.exists():
                    #     continue

